mapper.select:
SELECT
    id,
    order_id as "orderId",
    customer_id as "customerId",
    carrier,
    tracking_number as "trackingNumber",
    shipping_method as "shippingMethod",
    state_id as "stateId",
    delivery_attempts as "deliveryAttempts",
    estimated_delivery_date as "estimatedDeliveryDate",
    actual_delivery_date as "actualDeliveryDate",
    current_location as "currentLocation",
    created_time as "createdAt"
FROM shipments

    AND order_id = #{orderId}
    AND customer_id = #{customerId}
    AND carrier = #{carrier}
    AND shipping_method = #{shippingMethod}
    AND state_id = #{stateId}

${orderby} ${pagination}

SELECT count(*) FROM shipments

    AND order_id = #{orderId}
    AND customer_id = #{customerId}
    AND carrier = #{carrier}
    AND shipping_method = #{shippingMethod}
    AND state_id = #{stateId}

SELECT count(*) FROM shipments
WHERE carrier = #{carrier}
AND state_id = #{stateId}
